  1→package ast
  2→
  3→import "github.com/135yshr/meow/pkg/token"
  4→
  5→// Node is the interface for all AST nodes.
  6→type Node interface {
  7→	Pos() token.Position
  8→	nodeTag()
  9→}
 10→
 11→// Expr nodes produce a value.
 12→type Expr interface {
 13→	Node
 14→	exprTag()
 15→}
 16→
 17→// Stmt nodes perform an action.
 18→type Stmt interface {
 19→	Node
 20→	stmtTag()
 21→}
 22→
 23→// Program is the root AST node.
 24→type Program struct {
 25→	// Stmts is the list of top-level statements.
 26→	Stmts []Stmt
 27→}
 28→
 29→func (p *Program) Pos() token.Position {
 30→	if len(p.Stmts) > 0 {
 31→		return p.Stmts[0].Pos()
 32→	}
 33→	return token.Position{}
 34→}
 35→func (p *Program) nodeTag() {}
 36→
 37→// --- Expressions ---
 38→
 39→// IntLit represents an integer literal.
 40→type IntLit struct {
 41→	// Token is the source token.
 42→	Token token.Token
 43→	// Value is the parsed integer value.
 44→	Value int64
 45→}
 46→
 47→func (n *IntLit) Pos() token.Position { return n.Token.Pos }
 48→func (n *IntLit) nodeTag()            {}
 49→func (n *IntLit) exprTag()            {}
 50→
