391→// RangeStmt represents a range-based loop.
392→//
393→// Four forms are supported:
394→//
395→//	purr i (n)        — count form: i = 0, 1, …, n-1 (n iterations)
396→//	purr i (a..b)     — range form: i = a, a+1, …, b  (inclusive)
397→//	purr ch (str)     — string form: ch iterates over each rune as a one-char string
398→//	purr i, ch (str)  — string form with index: i is rune index, ch is the character
399→//
400→// In the count form, Start is nil and Inclusive is false.
401→// In the string forms, Start is nil, Inclusive is false, and End holds the string expression.
402→// The string form is distinguished at type-check time by the type of End.
403→type RangeStmt struct {
404→	// Token is the purr keyword token.
405→	Token token.Token
406→	// Var is the loop variable name (character in string form, counter in numeric forms).
407→	Var string
408→	// IndexVar is the optional index variable name for the two-variable string form.
409→	// Empty string means no index variable was specified.
410→	IndexVar string
411→	// Start is the range start expression, or nil for the count/string form.
412→	Start Expr
413→	// End is the upper bound expression (numeric forms) or the string expression (string form).
414→	End Expr
415→	// Inclusive is true for the a..b form (closed interval).
416→	Inclusive bool
417→	// Body is the list of statements in the loop body.
418→	Body []Stmt
419→}
420→
421→func (n *RangeStmt) Pos() token.Position { return n.Token.Pos }
422→func (n *RangeStmt) nodeTag()            {}
423→func (n *RangeStmt) stmtTag()            {}
