 62→// Func represents a function value.
 63→type Func struct {
 64→	// Name is the function name for display purposes.
 65→	Name string
 66→	// Fn is the underlying Go function implementation.
 67→	Fn func(args ...Value) Value
 68→	// Arity is the number of expected arguments. -1 means variadic (no currying).
 69→	Arity int
 70→}
