 72→// NewFunc creates a new Func value with the given name and implementation.
 73→// The function is variadic (Arity -1) and will not be auto-curried.
 74→// fn must not be nil; passing nil will panic.
 75→func NewFunc(name string, fn func(args ...Value) Value) *Func {
 76→	if fn == nil {
 77→		panic("Hiss! fn must not be nil, nya~")
 78→	}
 79→	return &Func{Name: name, Fn: fn, Arity: -1}
 80→}
 81→
 82→// NewFuncWithArity creates a new Func value with a fixed arity.
 83→// When called with fewer arguments than arity, the function is automatically
 84→// partially applied (curried).
 85→func NewFuncWithArity(name string, arity int, fn func(args ...Value) Value) *Func {
 86→	if fn == nil {
 87→		panic("Hiss! fn must not be nil, nya~")
 88→	}
 89→	return &Func{Name: name, Fn: fn, Arity: arity}
 90→}
 91→
 92→// PartialApply creates a new function that captures the given arguments and
 93→// waits for the remaining ones. The returned function's arity is reduced
 94→// by the number of supplied arguments.
 95→func PartialApply(fn *Func, args ...Value) *Func {
 96→	remaining := fn.Arity - len(args)
 97→	name := fmt.Sprintf("<partial %s %d/%d>", fn.Name, len(args), fn.Arity)
 98→	return NewFuncWithArity(name, remaining, func(moreArgs ...Value) Value {
 99→		allArgs := make([]Value, 0, len(args)+len(moreArgs))
100→		allArgs = append(allArgs, args...)
101→		allArgs = append(allArgs, moreArgs...)
102→		if fn.Arity > 0 && len(allArgs) < fn.Arity {
103→			return PartialApply(fn, allArgs...)
104→		}
105→		return fn.Fn(allArgs...)
106→	})
107→}
