224→// ToJSON serializes a Value to its JSON string representation.
225→func ToJSON(v Value) string {
226→	switch val := v.(type) {
227→	case *String:
228→		b, _ := json.Marshal(val.Val)
229→		return string(b)
230→	case *Int:
231→		return fmt.Sprintf("%d", val.Val)
232→	case *Float:
233→		return fmt.Sprintf("%g", val.Val)
234→	case *Bool:
235→		if val.Val {
236→			return "true"
237→		}
238→		return "false"
239→	case *NilValue:
240→		return "null"
241→	case *List:
242→		parts := make([]string, len(val.Items))
243→		for i, item := range val.Items {
244→			parts[i] = ToJSON(item)
245→		}
246→		return "[" + strings.Join(parts, ",") + "]"
247→	case *Map:
248→		keys := make([]string, 0, len(val.Items))
249→		for k := range val.Items {
250→			keys = append(keys, k)
251→		}
252→		sort.Strings(keys)
253→		parts := make([]string, 0, len(val.Items))
254→		for _, k := range keys {
255→			kb, _ := json.Marshal(k)
256→			parts = append(parts, string(kb)+":"+ToJSON(val.Items[k]))
257→		}
258→		return "{" + strings.Join(parts, ",") + "}"
259→	case *Kitty:
260→		parts := make([]string, len(val.FieldNames))
261→		for i, name := range val.FieldNames {
262→			kb, _ := json.Marshal(name)
263→			parts[i] = string(kb) + ":" + ToJSON(val.Fields[name])
264→		}
265→		return "{" + strings.Join(parts, ",") + "}"
266→	default:
267→		panic(fmt.Sprintf("Hiss! cannot serialize %s to JSON, nya~", v.Type()))
268→	}
269→}
