 45→		if len(args) < f.Arity {
 46→			return PartialApply(f, args...)
 47→		}
 48→		if len(args) > f.Arity {
 49→			panic(fmt.Sprintf("Hiss! %s expects %d arguments but got %d, nya~", f.Name, f.Arity, len(args)))
 50→		}
 51→	}
 52→	return f.Call(args...)
 53→}
