129→// Gag calls fn (a zero-argument Func) and recovers from any panic,
130→// returning the panic message wrapped in a Furball.
131→// If fn succeeds, its return value is returned as-is.
132→func Gag(fn Value) Value {
133→	f, ok := fn.(*Func)
