501→// hasReturnStmt checks whether a slice of statements contains any ReturnStmt (bring).
502→func hasReturnStmt(stmts []ast.Stmt) bool {
503→	for _, stmt := range stmts {
504→		switch s := stmt.(type) {
505→		case *ast.ReturnStmt:
506→			return true
507→		case *ast.IfStmt:
508→			if hasReturnStmt(s.Body) || hasReturnStmt(s.ElseBody) {
509→				return true
