560→func (c *Checker) checkRangeStmt(s *ast.RangeStmt) {
561→	if s.Start != nil {
562→		startType := types.Unwrap(c.inferExpr(s.Start))
563→		if !types.IsAny(startType) {
564→			if _, ok := startType.(types.IntType); !ok {
565→				c.addError(s.Token.Pos, "Range start must be int, got %s", startType)
566→			}
567→		}
568→	}
569→	endType := types.Unwrap(c.inferExpr(s.End))
570→	isListRange := false
571→	if !types.IsAny(endType) {
572→		if _, ok := endType.(types.ListType); ok && s.Start == nil && !s.Inclusive {
573→			isListRange = true
574→		} else if _, ok := endType.(types.StringType); ok && s.Start == nil && !s.Inclusive {
575→			c.addError(s.Token.Pos, "Cannot iterate over string directly, use to_runes() to convert first")
576→		} else if _, ok := endType.(types.IntType); !ok {
577→			c.addError(s.Token.Pos, "Range end must be int or list, got %s", endType)
578→		}
579→	}
580→	if s.IndexVar != "" && !isListRange {
581→		c.addError(s.Token.Pos, "Two-variable form is only allowed for list iteration")
582→	}
583→	c.pushScope()
584→	if isListRange {
585→		c.define(s.Var, types.AnyType{})
586→		c.info.VarTypes[s.Var] = types.AnyType{}
587→		if s.IndexVar != "" {
588→			c.define(s.IndexVar, types.IntType{})
589→			c.info.VarTypes[s.IndexVar] = types.IntType{}
590→		}
591→	} else {
592→		c.define(s.Var, types.IntType{})
593→		c.info.VarTypes[s.Var] = types.IntType{}
594→	}
595→	for _, stmt := range s.Body {
596→		c.checkStmt(stmt)
597→	}
598→	c.popScope()
599→}
