607→func (c *Checker) inferExprInner(expr ast.Expr) types.Type {
608→	switch e := expr.(type) {
609→	case *ast.IntLit:
610→		return types.IntType{}
611→	case *ast.FloatLit:
612→		return types.FloatType{}
613→	case *ast.StringLit:
614→		return types.StringType{}
615→	case *ast.BoolLit:
616→		return types.BoolType{}
617→	case *ast.NilLit:
618→		return types.NilType{}
619→	case *ast.Ident:
620→		return c.lookup(e.Name)
621→	case *ast.UnaryExpr:
622→		return c.inferUnary(e)
623→	case *ast.BinaryExpr:
624→		return c.inferBinary(e)
625→	case *ast.CallExpr:
626→		return c.inferCall(e)
627→	case *ast.LambdaExpr:
628→		return c.inferLambda(e)
629→	case *ast.ListLit:
630→		return c.inferList(e)
631→	case *ast.IndexExpr:
632→		leftType := c.inferExpr(e.Left)
633→		c.inferExpr(e.Index)
634→		if lt, ok := leftType.(types.ListType); ok {
635→			return lt.Elem
636→		}
637→		return types.AnyType{}
638→	case *ast.PipeExpr:
639→		c.inferExpr(e.Left)
640→		rightType := c.inferExpr(e.Right)
641→		if ft, ok := rightType.(types.FuncType); ok {
642→			return ft.Return
643→		}
644→		return rightType
645→	case *ast.CatchExpr:
646→		leftType := c.inferExpr(e.Left)
647→		rightType := c.inferExpr(e.Right)
648→		if !types.IsAny(leftType) {
649→			return leftType
650→		}
651→		if ft, ok := rightType.(types.FuncType); ok {
652→			return ft.Return
653→		}
654→		return rightType

