435→func (g *Generator) genTypedVarStmt(s *ast.VarStmt) string {
436→	t := g.getExprType(s.Value)
437→	if t != nil && !types.IsAny(t) {
438→		return fmt.Sprintf("var %s %s = %s", s.Name, goTypeString(t), g.genTypedExpr(s.Value))
