443→func (g *Generator) genTypedReturnStmt(s *ast.ReturnStmt) string {
444→	if s.Value == nil {
445→		return "return"
446→	}
447→	t := g.getExprType(s.Value)
448→	if t != nil && !types.IsAny(t) {
449→		return fmt.Sprintf("return %s", g.genTypedExpr(s.Value))
450→	}
451→	// Expression is AnyType (e.g. match expression) but function has a concrete return type.
452→	// Generate the expression with typed boxing, then unbox the meow.Value result.
453→	exprCode := g.genTypedExpr(s.Value)
454→	if g.currentReturnType != nil && !types.IsAny(g.currentReturnType) {
455→		return fmt.Sprintf("return %s", unboxToNative(exprCode, g.currentReturnType))
456→	}
457→	return fmt.Sprintf("return %s", exprCode)
458→}
