467→func (g *Generator) genTypedIf(s *ast.IfStmt) string {
468→	var b strings.Builder
469→	condType := g.getExprType(s.Condition)
470→	if condType != nil && !types.IsAny(condType) {
471→		fmt.Fprintf(&b, "if %s {\n", g.genTypedExpr(s.Condition))
472→	} else {
473→		fmt.Fprintf(&b, "if (%s).IsTruthy() {\n", g.genExpr(s.Condition))
474→	}
475→	for _, stmt := range s.Body {
476→		b.WriteString("\t")
477→		b.WriteString(g.genTypedStmt(stmt))
478→		b.WriteString("\n")
479→	}
480→	if len(s.ElseBody) > 0 {
481→		b.WriteString("} else {\n")
482→		for _, stmt := range s.ElseBody {
483→			b.WriteString("\t")
484→			b.WriteString(g.genTypedStmt(stmt))
485→			b.WriteString("\n")
486→		}
487→	}
488→	b.WriteString("}")
489→	return b.String()
490→}
