func (t TrickType) String() string { return t.Name }
func (t TrickType) Equals(other Type) bool {
	o, ok := other.(TrickType)
	return ok && t.Name == o.Name
}

// IsAny reports whether t is AnyType.
func IsAny(t Type) bool {
	_, ok := t.(AnyType)
